SELECT pg_notify('order_updates', row_to_json(NEW)::text);

generate_series.syntax:
SELECT * FROM generate_series(1, 10) AS n;

-- Calendar of months:
SELECT generate_series(
  '2024-01-01'::date,
  '2024-12-01',
  '1 month'
)::date AS month;

mysql.syntax:
WITH RECURSIVE n AS (
  SELECT 1 AS val
  UNION ALL
  SELECT val + 1 FROM n WHERE val < 10
)
SELECT val FROM n;

postgresql.syntax:
SELECT generate_series(1, 10);
SELECT generate_series(1, 10, 2);  -- odd numbers: 1,3,5,7,9
SELECT generate_series(
  '2024-01-01'::timestamptz,
  '2024-12-31',
  '1 month'
) AS month;

sqlserver.syntax:
