SELECT value FROM GENERATE_SERIES(1, 10, 2);
-- Requires: ALTER DATABASE db SET COMPATIBILITY_LEVEL = 160;

sqlite.syntax:
WITH RECURSIVE n(val) AS (
  SELECT 1
  UNION ALL
  SELECT val + 1 FROM n WHERE val < 10
)
SELECT val FROM n;

