exclusion constraints.syntax:
CREATE TABLE bookings (
  room   INT,
  during TSRANGE,
  EXCLUDE USING gist (room WITH =, during WITH &&)
);

mysql.syntax:
-- Not supported.
SELECT * FROM bookings
WHERE start_date < '2024-02-01' AND end_date > '2024-01-01';

postgresql.syntax:
SELECT '[1,5)'::int4range @> 3;   -- true
SELECT '[1,5)'::int4range && '[3,8)'::int4range;  -- true

CREATE TABLE events (
  name   TEXT,
  during TSRANGE
);
CREATE INDEX ON events USING gist (during);

-- Query events overlapping a window:
SELECT * FROM events
WHERE during && '[2024-01-01,2024-02-01)'::tsrange;

