FROM employees;

SELECT STATS_MODE(dept_id) AS most_common_dept FROM employees;

row-level security.syntax:
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY own_orders ON orders
  USING (customer_id = current_setting('app.user_id')::int);

mysql.syntax:
-- Not supported. Workaround: a view with a WHERE clause
CREATE VIEW my_orders AS
  SELECT * FROM orders WHERE customer_id = GET_USER_ID();

postgresql.syntax:
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders FORCE ROW LEVEL SECURITY;

-- Allow users to see only their own rows:
CREATE POLICY own_orders ON orders FOR SELECT
  USING (customer_id = current_setting('app.user_id')::int);

-- Allow admins to see everything:
CREATE POLICY admin_all ON orders FOR ALL TO admin_role
  USING (true);

sqlserver.syntax:
CREATE FUNCTION dbo.rls_fn(@cust_id INT)
RETURNS TABLE WITH SCHEMABINDING AS
RETURN SELECT 1 AS ok WHERE @cust_id = CAST(SESSION_CONTEXT(N'user_id') AS INT);

CREATE SECURITY POLICY dbo.OrderPolicy
ADD FILTER PREDICATE dbo.rls_fn(customer_id) ON dbo.orders
WITH (STATE = ON);

oracle.syntax:
CREATE FUNCTION rls_policy(schema_v VARCHAR2, tbl VARCHAR2)
RETURN VARCHAR2 AS
BEGIN RETURN 'customer_id = SYS_CONTEXT(''USERENV'',''SESSION_USER'')'; END;

BEGIN
  DBMS_RLS.ADD_POLICY('SCOTT','ORDERS','own_orders','SCOTT','rls_policy');
END;

