  SELECT *, ROW_NUMBER() OVER (PARTITION BY dept_id ORDER BY salary DESC) AS rn
  FROM employees
)
SELECT * FROM ranked WHERE rn = 1;

regex.syntax:
-- Varies significantly by engine.
-- PostgreSQL:
SELECT * FROM tbl WHERE col ~ '^[A-Z]';

-- MySQL:
SELECT * FROM tbl WHERE col REGEXP '^[A-Z]';

postgresql.syntax:
SELECT * FROM tbl WHERE col ~ '^[A-Z]';          -- case-sensitive
SELECT * FROM tbl WHERE col ~* '^[a-z]';         -- case-insensitive
SELECT regexp_match('foo123', '[0-9]+');          -- {123}
SELECT regexp_replace('foo123', '[0-9]+', '#');   -- 'foo#'
SELECT * FROM regexp_split_to_table('a,b,c', ',') AS t(val);

oracle.syntax:
SELECT * FROM tbl WHERE REGEXP_LIKE(col, '^[A-Z]');
SELECT * FROM tbl WHERE REGEXP_LIKE(col, '^[a-z]', 'i');
SELECT REGEXP_REPLACE('foo123', '[0-9]+', '#') FROM DUAL;  -- 'foo#'
SELECT REGEXP_SUBSTR('foo123bar', '[0-9]+')    FROM DUAL;  -- '123'

postgresql.syntax:
SELECT '2024-01-15'::date + INTERVAL '7 days';          -- 2024-01-22
SELECT NOW() - INTERVAL '1 month 2 days';
SELECT NOW() + INTERVAL '2 hours 30 minutes';
SELECT AGE('2024-06-01'::date, '2023-01-15'::date);    -- 1 year 4 mons 17 days

sqlserver.syntax:
SELECT DATEADD(day,    7,  '2024-01-15');   -- 2024-01-22
SELECT DATEADD(month, -1, '2024-01-15');   -- 2023-12-15
SELECT DATEADD(hour,  2,  GETDATE());
SELECT DATEADD(year,  1,  GETDATE());

oracle.syntax:
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD')           FROM DUAL; -- '2024-03-15'
SELECT TO_CHAR(SYSDATE, 'DD/MM/YYYY')           FROM DUAL; -- '15/03/2024'
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS') FROM DUAL;
SELECT TO_CHAR(SYSDATE, 'Day, Month DD YYYY')    FROM DUAL;

primary key.syntax:
CREATE TABLE users (
  id   INT PRIMARY KEY,
  name TEXT NOT NULL
);

-- Or as a named table constraint:
CREATE TABLE users (
  id   INT,
  name TEXT,
  CONSTRAINT pk_users PRIMARY KEY (id)
);

mysql.syntax:
CREATE TABLE users (
  id   INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL
) ENGINE=InnoDB;

-- Composite:
CREATE TABLE order_items (
  order_id INT,
  item_id  INT,
  PRIMARY KEY (order_id, item_id)
);

postgresql.syntax:
-- Modern (PG 10+):
CREATE TABLE users (
  id   INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  name TEXT NOT NULL
);

-- Legacy SERIAL style:
CREATE TABLE users (
  id   SERIAL PRIMARY KEY,
  name TEXT NOT NULL
);

sqlserver.syntax:
CREATE TABLE users (
  id   INT IDENTITY(1,1) PRIMARY KEY,
  name NVARCHAR(100) NOT NULL
);

-- Non-clustered PK:
CREATE TABLE users (
  id INT PRIMARY KEY NONCLUSTERED,
  name NVARCHAR(100)
);

oracle.syntax:
-- Modern (12c+):
CREATE TABLE users (
  id   NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  name VARCHAR2(100) NOT NULL
);

-- Legacy sequence approach:
CREATE SEQUENCE user_seq START WITH 1 INCREMENT BY 1;
CREATE TABLE users (id NUMBER DEFAULT user_seq.NEXTVAL PRIMARY KEY, name VARCHAR2(100));

sqlite.syntax:
CREATE TABLE users (
  id   INTEGER PRIMARY KEY,      -- auto-increment via rowid alias
  name TEXT NOT NULL
);

-- AUTOINCREMENT prevents rowid reuse:
CREATE TABLE users (
  id   INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT
);

mysql.syntax:
CREATE TABLE orders (
  id          INT AUTO_INCREMENT PRIMARY KEY,
  customer_id INT,
  FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
    ON UPDATE RESTRICT
) ENGINE=InnoDB;

-- Disable FK checks for bulk loads:
SET FOREIGN_KEY_CHECKS = 0;

postgresql.syntax:
CREATE TABLE orders (
  id          SERIAL PRIMARY KEY,
  customer_id INT REFERENCES customers(id) ON DELETE CASCADE
);

-- Deferrable constraint:
ALTER TABLE orders ADD CONSTRAINT fk_customer
  FOREIGN KEY (customer_id) REFERENCES customers(id)
  DEFERRABLE INITIALLY DEFERRED;

sqlserver.syntax:
CREATE TABLE orders (
  id          INT IDENTITY PRIMARY KEY,
  customer_id INT,
  CONSTRAINT fk_orders_customer
    FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
);

-- Disable for bulk load:
ALTER TABLE orders NOCHECK CONSTRAINT fk_orders_customer;

oracle.syntax:
CREATE TABLE orders (
  id          NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  customer_id NUMBER,
  CONSTRAINT fk_orders_customer
    FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
);

-- Recommended: index the FK column manually
CREATE INDEX idx_orders_cust ON orders(customer_id);

sqlite.syntax:
-- REQUIRED: enable FK enforcement first
PRAGMA foreign_keys = ON;

CREATE TABLE orders (
  id          INTEGER PRIMARY KEY,
  customer_id INTEGER REFERENCES customers(id) ON DELETE CASCADE
);

mysql.syntax:
CREATE TABLE employees (
  id     INT PRIMARY KEY,
  salary DECIMAL(10,2),
  status VARCHAR(20),
  CONSTRAINT chk_salary CHECK (salary > 0),
  CONSTRAINT chk_status CHECK (status IN ('active', 'inactive', 'pending'))
);

-- Add to existing table:
ALTER TABLE employees ADD CONSTRAINT chk_age CHECK (age >= 18);

postgresql.syntax:
CREATE TABLE employees (
  id     SERIAL PRIMARY KEY,
  salary NUMERIC CHECK (salary > 0),
  status TEXT   CHECK (status IN ('active', 'inactive', 'pending'))
);

-- Add without scanning existing rows:
ALTER TABLE employees
  ADD CONSTRAINT chk_salary CHECK (salary > 0) NOT VALID;
ALTER TABLE employees VALIDATE CONSTRAINT chk_salary;

sqlserver.syntax:
CREATE TABLE employees (
  id     INT IDENTITY PRIMARY KEY,
  salary DECIMAL(10,2) CHECK (salary > 0),
  status NVARCHAR(20)  CHECK (status IN ('active','inactive','pending'))
);

-- Add without checking existing rows:
ALTER TABLE employees
  WITH NOCHECK ADD CONSTRAINT chk_salary CHECK (salary > 0);

oracle.syntax:
CREATE TABLE employees (
  id     NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  salary NUMBER       CONSTRAINT chk_salary CHECK (salary > 0),
  status VARCHAR2(20) CONSTRAINT chk_status CHECK (status IN ('active','inactive','pending'))
);

ALTER TABLE employees ADD CONSTRAINT chk_age CHECK (age >= 18) ENABLE NOVALIDATE;

sqlite.syntax:
CREATE TABLE employees (
  id     INTEGER PRIMARY KEY,
  salary REAL    CHECK (salary > 0),
  status TEXT    CHECK (status IN ('active', 'inactive', 'pending'))
);

-- SQLite allows subqueries in CHECK (unusual):
CREATE TABLE items (
  cat_id INT CHECK (cat_id IN (SELECT id FROM categories))
);

unique constraint.syntax:
CREATE TABLE users (
  id    INT PRIMARY KEY,
  email TEXT UNIQUE,
  username TEXT,
  CONSTRAINT uq_username UNIQUE (username)
);

mysql.syntax:
CREATE TABLE users (
  id       INT AUTO_INCREMENT PRIMARY KEY,
  email    VARCHAR(255) UNIQUE,
  username VARCHAR(50)
);

-- Composite unique:
ALTER TABLE users ADD CONSTRAINT uq_name_email UNIQUE (username, email);

-- Drop:
ALTER TABLE users DROP INDEX uq_name_email;

postgresql.syntax:
CREATE TABLE users (
  id    SERIAL PRIMARY KEY,
  email TEXT UNIQUE
);

-- PG 15+: treat NULL as equal (only one NULL allowed):
CREATE UNIQUE INDEX ON users (email) NULLS NOT DISTINCT;

-- Composite:
ALTER TABLE users ADD CONSTRAINT uq_name UNIQUE (first_name, last_name);

sqlserver.syntax:
CREATE TABLE users (
  id    INT IDENTITY PRIMARY KEY,
  email NVARCHAR(255) UNIQUE
);

-- Allow multiple NULLs via filtered index:
CREATE UNIQUE INDEX uq_email ON users(email) WHERE email IS NOT NULL;

-- Drop:
ALTER TABLE users DROP CONSTRAINT uq_users_email;

oracle.syntax:
CREATE TABLE users (
  id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  email VARCHAR2(255) UNIQUE
);

-- Named constraint:
ALTER TABLE users ADD CONSTRAINT uq_email UNIQUE (email);

-- Disable without dropping:
ALTER TABLE users DISABLE CONSTRAINT uq_email;

sqlite.syntax:
CREATE TABLE users (
  id    INTEGER PRIMARY KEY,
  email TEXT UNIQUE
);

-- Composite:
CREATE TABLE memberships (
  user_id INT,
  group_id INT,
