sqlserver.syntax:
-- Modern standard:
SELECT * FROM tbl ORDER BY id
OFFSET 20 ROWS FETCH NEXT 10 ROWS ONLY;

-- Legacy TOP (all versions):
SELECT TOP 10 * FROM tbl ORDER BY id;
SELECT TOP 10 PERCENT * FROM tbl ORDER BY id;
SELECT TOP 10 WITH TIES * FROM tbl ORDER BY id;

oracle.syntax:
-- Modern (12c+):
SELECT * FROM tbl ORDER BY id
FETCH FIRST 10 ROWS ONLY;

SELECT * FROM tbl ORDER BY id
OFFSET 20 ROWS FETCH NEXT 10 ROWS ONLY;

-- Legacy ROWNUM (pre-12c — must wrap in subquery):
