json extract.syntax:
-- MySQL / SQLite path syntax:
SELECT JSON_EXTRACT(data, '$.name') AS name
FROM users;

-- PostgreSQL operator shorthand:
SELECT data->>'name' AS name
FROM users;

-- SQL Server / Oracle:
SELECT JSON_VALUE(data, '$.name') AS name
FROM users;

postgresql.syntax:
-- Single key, JSON result:
SELECT data->'name'            AS name_json
FROM users;

-- Single key, text result:
SELECT data->>'name'           AS name_text
FROM users;

-- Nested path, JSON result:
SELECT data#>'{address,city}'  AS city_json
FROM users;

-- Nested path, text result:
SELECT data#>>'{address,city}' AS city_text
FROM users;

-- Function form:
SELECT jsonb_extract_path_text(data, 'address', 'city') AS city
FROM users;

-- Key extraction:
SELECT data->'name'             AS name_json,
       data->>'name'            AS name_text
FROM users;

-- Array index:
SELECT data->'tags'->0          AS first_tag_json,
       data->'tags'->>0         AS first_tag_text
FROM posts;

-- Nested path (path array):
SELECT data#>'{address,city}'   AS city_json,
       data#>>'{address,city}'  AS city_text
FROM users;

-- jsonb containment / existence:
SELECT * FROM users WHERE data @> '{"role":"admin"}';
SELECT * FROM users WHERE data ? 'email';
SELECT * FROM users WHERE data ?| ARRAY['admin','superuser'];

sequence / autoincrement.syntax:
-- Standard SQL (PostgreSQL 10+, SQL Server 2012+, Oracle 12c+):
CREATE TABLE orders (
    id INTEGER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    amount DECIMAL(10,2)
);

-- MySQL:
CREATE TABLE orders (
    id INT AUTO_INCREMENT PRIMARY KEY,
    amount DECIMAL(10,2)
);

mysql.syntax:
-- Basic AUTO_INCREMENT:
CREATE TABLE orders (
    id    INT AUTO_INCREMENT PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Custom start value:
CREATE TABLE orders (
    id    INT AUTO_INCREMENT PRIMARY KEY,
    total DECIMAL(10,2)
) AUTO_INCREMENT = 1000;

-- Reset/set current value:
ALTER TABLE orders AUTO_INCREMENT = 5000;

-- Get last inserted ID:
SELECT LAST_INSERT_ID();

postgresql.syntax:
-- SQL standard (recommended, PG 10+):
CREATE TABLE orders (
    id    INTEGER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    total DECIMAL(10,2)
);

-- GENERATED BY DEFAULT (allows override):
CREATE TABLE orders (
    id    INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Legacy SERIAL (still common):
CREATE TABLE orders (
    id    SERIAL PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Standalone sequence:
CREATE SEQUENCE order_id_seq START 1000 INCREMENT 1;
SELECT nextval('order_id_seq');
SELECT currval('order_id_seq');

sqlserver.syntax:
-- IDENTITY column:
CREATE TABLE orders (
    id    INT IDENTITY(1,1) PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Get last inserted ID:
SELECT SCOPE_IDENTITY() AS new_id;

-- OUTPUT clause alternative:
INSERT INTO orders (total)
OUTPUT INSERTED.id
VALUES (99.99);

-- Standalone SEQUENCE (2012+):
CREATE SEQUENCE order_seq START WITH 1000 INCREMENT BY 1;
SELECT NEXT VALUE FOR order_seq;

oracle.syntax:
-- Standard identity column (12c+):
CREATE TABLE orders (
    id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    total NUMBER(10,2)
);

-- GENERATED BY DEFAULT (allows override):
CREATE TABLE orders (
    id    NUMBER GENERATED BY DEFAULT AS IDENTITY START WITH 1000 PRIMARY KEY,
    total NUMBER(10,2)
);

-- Legacy sequence approach (pre-12c):
CREATE SEQUENCE order_id_seq START WITH 1 INCREMENT BY 1 NOCACHE;

INSERT INTO orders (id, total)
VALUES (order_id_seq.NEXTVAL, 99.99);

SELECT order_id_seq.CURRVAL FROM dual;

sqlite.syntax:
-- INTEGER PRIMARY KEY (implicit autoincrement, recommended):
CREATE TABLE orders (
    id    INTEGER PRIMARY KEY,
    total REAL
);

-- AUTOINCREMENT keyword (strict no-reuse guarantee):
CREATE TABLE orders (
    id    INTEGER PRIMARY KEY AUTOINCREMENT,
    total REAL
);

-- Get last inserted rowid:
SELECT last_insert_rowid();

nullif.syntax:
-- Avoid division by zero:
SELECT total_revenue / NULLIF(total_orders, 0) AS avg_order_value
FROM sales_summary;

-- Convert empty string to NULL:
SELECT NULLIF(email, '') AS email
FROM users;

postgresql.syntax:
-- Division-by-zero guard:
SELECT revenue / NULLIF(costs, 0) AS margin
FROM financials;

-- Combine with COALESCE for default value:
SELECT COALESCE(NULLIF(nickname, ''), full_name) AS display_name
FROM users;

-- Date comparison:
SELECT NULLIF(end_date, '9999-12-31'::date) AS actual_end
FROM contracts;

sqlite.syntax:
-- Division-by-zero guard:
SELECT price / NULLIF(quantity, 0) AS unit_cost
FROM inventory;

-- Convert sentinel value to NULL:
SELECT NULLIF(category, 'UNKNOWN') AS category
FROM products;

greatest / least.syntax:
-- Clamp a value between a min and max:
SELECT GREATEST(LEAST(score, 100), 0) AS clamped_score
FROM results;

-- Latest of two dates:
SELECT GREATEST(start_date, effective_date) AS use_date
FROM contracts;

sqlserver.syntax:
-- SQL Server 2022+:
SELECT GREATEST(q1_sales, q2_sales, q3_sales) AS peak_quarter
FROM quarterly_results;

SELECT LEAST(ship_date, delivery_date) AS earlier_date
FROM shipments;

-- Workaround for SQL Server 2019 and earlier (2 values):
SELECT IIF(q1 > q2, q1, q2) AS greatest_2
FROM quarterly_results;

-- Workaround for SQL Server 2019 and earlier (3+ values via VALUES):
SELECT (SELECT MAX(v) FROM (VALUES (q1), (q2), (q3)) AS t(v)) AS peak
FROM quarterly_results;

oracle.syntax:
SELECT GREATEST(q1_sales, q2_sales, q3_sales, q4_sales) AS peak_quarter
FROM quarterly_results;

-- Clamp:
SELECT GREATEST(LEAST(score, 100), 0) AS clamped_score
FROM exam_results;

-- NULL propagation:
SELECT GREATEST(1, NULL, 3) FROM dual; -- Returns NULL

-- NVL workaround when NULLs must be handled:
SELECT GREATEST(NVL(col1, 0), NVL(col2, 0)) AS safe_greatest
FROM t;
